CREATE OR REPLACE FUNCTION fpa_com_check_leap_year (adt_date timestamp(0)) RETURNS integer AS $body$
DECLARE

  li_return integer;
  li_year integer;

BEGIN
-- return 1-เป็น , 0 - ไม่เป็น
 /* เงื่อนไขการเป็นปีอธิกสุรทิน
  1.ถ้าปี ค.ศ. ใดหารด้วย 4 ไม่ลงตัวจะ ไม่เป็นปีอธิกสุรทิน
  2.ถ้าปีใดหารด้วย 4 ลงตัวและหารด้วย 100 ลงตัว แต่หารด้วย 400 ไม่ลงตัว ปี ค.ศ. นั้นจะ ไม่เป็นปีอธิกสุรทิน
  3.ถ้าปี ค.ศ. ใด หารด้วย 4 ลงตัว แต่หารด้วย 100 ไม่ลงตัว ค.ศ.นั้นจะ เป็นปีอธิกสุรทิน
  4.ถ้าปี ค.ศ. ใด หารด้วย 4 ลงตัว และหารด้วย 400 ลงตัว ปี ค.ศ.นั้นจะ เป็นปีอธิกสุรทิน */
  li_year := extract(year from adt_date);

  if mod(li_year,4) = 0 and mod(li_year,100) > 0  then
    li_return := 1;
  elsif mod(li_year,4) = 0 and mod(li_year,400) = 0  then
    li_return := 1;
  else
    li_return := 0;
  end if;


  RETURN li_return;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
